-- ── LimeSurvey ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source online survey software offering a free self-hosted edition and a paid cloud-hosted version.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted Community Edition)$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$18-20 employees$q$, company_size),
  headquarters = COALESCE($q$Hamburg, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$and 100+ other languages via localization$q$]::text[],
  seo_title = COALESCE($q$LimeSurvey Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LimeSurvey is an open-source survey tool with a free self-hosted edition and paid cloud plans from 29 euros per month. Compare features, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LimeSurvey is one of the longest-running open-source survey platforms on the web, tracing its origins to a SourceForge project called PHPSurveyor, launched on February 20, 2003 by Australian software developer Jason Cleeland, with its first public release (version 0.93) following on March 5, 2003. The project gained early real-world visibility when it was used during the 2004 U.S. presidential election to help track and report voting irregularities, reportedly logging over 13,500 incidents within the first ten hours of voting, an early demonstration of the tool's capacity for high-volume, time-sensitive data collection. On May 17, 2007, the project was renamed from PHPSurveyor to LimeSurvey specifically to simplify software licensing by removing the ambiguous reference to PHP from the name. The software underwent a complete architectural rewrite in 2012, moving to an MVC (model-view-controller) structure built on the Yii PHP framework, and later adopted the Twig templating engine with the version 3.0 release in December 2017. To formalize commercial stewardship of the increasingly popular open-source project, LimeSurvey GmbH was founded in August 2015 as a limited liability company headquartered in Hamburg, Germany, co-founded by long-time project leader Carsten Schmitz, who continues to lead the company. LimeSurvey GmbH today operates with a lean team of roughly 18 to 20 employees, reflecting an efficient, services-and-subscription-driven business model rather than venture-backed rapid scaling; public reporting has cited annual revenue in the low single-digit millions of dollars. LimeSurvey's architecture remains PHP-based and database-agnostic, supporting MySQL, SQLite, PostgreSQL or Microsoft SQL Server as a backend, and the survey engine itself is localized into 116 languages and dialects, making it one of the most linguistically comprehensive survey tools available, open source or commercial. The product is offered in two primary forms. The Community Edition is the free, GPL-licensed, self-hosted version that any organization or individual can download, install and run on their own server infrastructure with no feature restrictions tied to payment, only the requirement of self-managed hosting and community-based support. The second form, LimeSurvey Cloud, is a fully hosted SaaS offering, comparable in convenience to commercial competitors like SurveyMonkey or Typeform, but priced differently: rather than gating features behind a paywall, LimeSurvey Cloud's pricing scales primarily with the number of survey responses collected per period, which the company positions as a fairer model for organizations with unpredictable but occasionally high response volumes. As of the most recent published pricing, LimeSurvey Cloud offers a free entry tier with a limited number of monthly responses, followed by four paid plans: Basic at approximately 34 euros per month for one admin user, 1,000 responses per month and 250 MB of storage; Expert at approximately 29 euros per month when billed annually (348 euros per year), supporting up to three admin users, 10,000 responses per year, 1 GB of storage, white-label branding and email support; Business at approximately 75 euros per month billed annually (900 euros per year), supporting 5 to 10 admin users, 50,000 responses per year, 3 GB of storage, an alias domain and priority support; and Corporate, a custom-quoted tier for organizations needing SSO via LDAP or SAML, dedicated servers and VIP support. LimeSurvey also offers discretionary discounts of 30 percent for teachers and charitable organizations and 50 percent for students, and customers can choose among seven hosting regions including Germany, Finland, the UK, the US, Canada and Australia, which is a meaningful differentiator for organizations with GDPR or data-residency requirements. LimeSurvey's target audience spans academic researchers, market researchers, public sector agencies, nonprofits and businesses that need advanced survey logic (branching, quotas, randomization, multilingual surveys) without the recurring per-response fees of commercial SaaS survey tools, or that specifically require an on-premises, auditable, self-hosted deployment for compliance reasons. Its principal competitors include SurveyMonkey, Typeform, Qualtrics, Google Forms and Alchemer (formerly SurveyGizmo); LimeSurvey differentiates itself from all of these primarily through its open-source licensing and self-hosting option, its response-based rather than feature-gated cloud pricing, and its unusually deep localization into over a hundred languages, which makes it a common choice for international research consortia, universities and multilingual public-sector surveys where commercial alternatives either lack language coverage or charge a premium for it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ea21bbfa-3554-42a3-a4a1-7aac41c0974f';

