-- ── Linear ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Fast, keyboard-driven issue tracking and project management tool built for software engineering teams.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Roughly 100-250 employees (2026, estimates vary by source)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Linear Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Linear is a fast issue tracking tool for software teams, valued at 1.25 billion dollars. Compare Linear pricing, features and alternatives like Jira and Asana.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Linear is a project and issue tracking platform purpose-built for software development teams, founded in 2019 by Karri Saarinen (CEO), Tuomas Artman (CTO) and Jori Lallo, and headquartered in San Francisco, California. Saarinen previously worked as a design lead at Airbnb and Coinbase, while Artman brought engineering leadership experience from Uber, and the founding team's product design pedigree is reflected heavily in Linear's identity: the company built its reputation on speed, keyboard-first navigation, and an opinionated, minimalist interface that stands in deliberate contrast to older, more configurable but heavier tools like Jira. Linear's funding history reflects strong and sustained investor confidence in this positioning. The company raised a 4.2 million dollar seed round led by Sequoia Capital in November 2019, followed by a 13 million dollar Series A also from Sequoia in December 2020, a 35 million dollar Series B led by Accel in September 2023, and most recently an 82 million dollar Series C led by Accel in June 2025, which valued the company at 1.25 billion dollars, officially making Linear a unicorn. Total funding raised across all rounds stands at approximately 134.2 million dollars, with Sequoia Capital and Accel serving as the primary institutional backers throughout the company's growth, alongside other participants including 01 Advisors, Seven Seven Six, Designer Fund and Index Ventures. As of 2026, employee count estimates vary meaningfully by data source, ranging from roughly 118 to 234 people, reflecting the imprecision common in third-party headcount tracking for private companies, but Linear is broadly understood to operate with a lean, product-focused team relative to its valuation and customer base. The company states that it serves more than 33,000 organizations, including notable customers such as OpenAI, Coinbase and Ramp, positioning Linear firmly as the default issue tracker for many venture-backed, engineering-driven technology companies. Architecturally and philosophically, Linear is built around what the company calls the Linear Method, a set of opinionated best practices for software development workflows that emphasizes short, focused work cycles, clear ownership of issues, and minimizing process overhead; this is reflected directly in product features like Cycles (Linear's version of sprints), Triage (a queue for incoming issues that need classification), and a roadmap and project tracking layer that connects individual issues to broader initiatives. The product is known for its speed and responsiveness, built with a local-first architecture that allows near-instant interactions even with large issue databases, and for extensive keyboard shortcuts that let experienced users navigate and manage issues without touching a mouse. Linear's pricing follows a four-tier freemium model. The Free plan costs nothing, supports unlimited members, and allows up to 2 teams and 250 issues, along with access to Linear's agent platform, making it viable for small teams or early-stage startups. The Basic plan costs 10 dollars per user per month when billed yearly and adds unlimited issues, support for up to 5 teams, unlimited file uploads and admin roles. The Business plan, at 16 dollars per user per month billed yearly, is the most feature-rich self-serve tier, adding unlimited teams, private teams and guest accounts, Triage Intelligence (AI-assisted issue triage), Linear Agent automations (in beta), Code Intelligence (in beta, connecting issues to code changes), Linear Insights analytics, Linear Asks, and native integrations with Zendesk and Intercom. At the top, an Enterprise plan offers custom, annual-only pricing with invoice and purchase-order billing, SAML and SCIM support for identity management, granular admin controls, enterprise-grade security certifications, and dedicated migration and onboarding support with a named account manager. Linear has increasingly layered AI capabilities into its product, including AI-assisted triage and coding-session features that draw on separate usage-based credits, reflecting the broader industry shift toward embedding AI agents directly into developer workflow tools. Linear's target audience is squarely software engineering and product teams at technology companies, particularly those that value design quality, speed and a curated feature set over Jira's extensive but often overwhelming configurability. Its main competitors include Atlassian's Jira, the long-standing incumbent in enterprise issue tracking, as well as Asana, ClickUp, Monday.com, Height, Shortcut and Trello. Linear differentiates itself from this field primarily through its uncompromising focus on speed and interface craft, its opinionated rather than infinitely configurable workflow model, and its strong brand affinity among high-growth, well-funded startups and engineering-culture-forward companies, a positioning reinforced by its billion-dollar-plus valuation and backing from top-tier venture firms like Sequoia and Accel.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e762d0b5-3f6a-4165-89d8-5d2a4889217d';

