-- ── LinkedIn Recruiter ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LinkedIn's flagship talent sourcing platform giving recruiters advanced search, InMail and AI-assisted candidate matching.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (Recruiter Lite from approximately $170/month)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$20,000+ employees (LinkedIn, a Microsoft subsidiary)$q$, company_size),
  headquarters = COALESCE($q$Sunnyvale, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and 20+ other languages via LinkedIn platform localization$q$]::text[],
  seo_title = COALESCE($q$LinkedIn Recruiter Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LinkedIn Recruiter is LinkedIn's talent sourcing platform with 40+ search filters and AI matching. Compare Recruiter Lite and Corporate pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LinkedIn Recruiter is the flagship talent sourcing and candidate outreach product within LinkedIn Talent Solutions, the business-facing arm of LinkedIn, the professional networking platform founded in 2003 by Reid Hoffman and acquired by Microsoft in 2016 for approximately 26.2 billion dollars in one of the largest technology acquisitions of that era. LinkedIn itself is headquartered in Sunnyvale, California, and operates as a wholly owned Microsoft subsidiary with more than 20,000 employees globally and over 1 billion registered members, giving LinkedIn Recruiter access to by far the largest structured professional talent pool of any recruiting platform on the market. LinkedIn Recruiter is not a standalone startup but a mature enterprise product line within a much larger corporate structure, and its competitive advantage rests almost entirely on this proprietary, first-party access to LinkedIn's member graph, including real-time signals about job-seeking activity, skills, work history and professional connections that third-party sourcing tools can only approximate through public data scraping or partial API access. The product is offered in tiered subscription levels rather than a single SKU. Recruiter Lite is the entry-level offering, priced at roughly 170 dollars per month, and is designed for individual recruiters or hiring managers who hire less frequently; it provides 20 search filters, visibility limited to a user's third-degree LinkedIn connections, and an allotment of about 30 InMail messages per month for direct candidate outreach. At the top of the individual-seat tier is Recruiter Corporate, sometimes marketed as Recruiter Professional Services or RPS+ depending on the customer segment, priced at approximately 900 dollars per month or roughly 10,800 dollars annually per seat, since LinkedIn requires each recruiter or sourcer to hold an individual license with no shared or floating seats available, a licensing structure that causes total spend to scale linearly and sometimes steeply with team size. Recruiter Corporate unlocks LinkedIn's full 40-plus advanced search filters spanning job titles, locations, skills, industries, languages and network relationships, unrestricted access across LinkedIn's member network rather than being limited by connection degree, a substantially larger InMail allotment of 100 to 150 messages per month, Recommended Matches (an algorithmic feature that surfaces candidates a recruiter has not yet actively searched for, based on job postings and real-time hiring activity), team collaboration and analytics tools, and integrations with applicant tracking systems (ATS) and other LinkedIn recruiting products. LinkedIn has increasingly layered AI capabilities into Recruiter through an add-on called Hiring Assistant, which automates repetitive recruiting tasks such as reviewing candidate profiles, sending prescreening questions, and drafting outreach messages, while explicitly keeping a human recruiter in control of final decisions, a positioning LinkedIn frames as responsible or human-centered AI in contrast to fully autonomous sourcing tools. LinkedIn cites internal performance data claiming that Hiring Assistant saves recruiters more than four hours per user per role and reduces the number of profiles a recruiter must manually review by 62 percent, while qualified candidates can typically be surfaced in under five minutes on average using Recruiter's search and matching tools. Separately, LinkedIn also sells Talent Insights, a standalone labor-market analytics product providing data on hiring trends, talent availability and competitor hiring activity, which is priced independently of Recruiter and typically ranges from around 6,000 to 20,000 dollars per year depending on scope. LinkedIn also maintains specialized go-to-market variants of its talent products tailored to staffing agencies, nonprofits, healthcare organizations, higher education institutions and government agencies, reflecting the breadth of its enterprise customer base. LinkedIn Recruiter's target audience spans individual recruiters and hiring managers at small companies who use Recruiter Lite for occasional hiring needs, through dedicated in-house talent acquisition teams and staffing agencies that require Recruiter Corporate's full search depth, higher InMail volume and team analytics for high-volume or specialized hiring. LinkedIn positions Recruiter's core value proposition around measurable hiring quality, citing data that candidates sourced through LinkedIn are 37 percent less likely to leave their role within the first year compared to hires sourced through other channels. In the competitive recruiting technology landscape, LinkedIn Recruiter's most direct competitors include Indeed's employer and resume database products, ZipRecruiter, and newer AI-native sourcing platforms such as hireEZ, SeekOut and Gem, along with the sourcing capabilities built into applicant tracking systems like Greenhouse. LinkedIn Recruiter's key differentiator against all of these alternatives remains structural rather than purely feature-based: no competitor has comparable first-party access to LinkedIn's billion-plus-member professional graph and its associated real-time job-seeking and engagement signals, which is why LinkedIn Recruiter remains, by most industry accounts, the de facto industry-standard sourcing tool despite its high per-seat cost and lack of publicly transparent pricing for its top tier.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5edf3623-fbe7-4031-ae06-d836d7bc2e06';

