INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Low-code form and application builder$q$, $q$Build database-driven forms, views and workflows for CRM, DMS or ERP-style applications without writing a full custom application from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Multi-database connectivity$q$, $q$Connects via PDO and unixODBC to PostgreSQL, MySQL, MSSQL, Oracle and SAP MaxDB or HANA, letting IT teams unify access to heterogeneous enterprise data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Document management (DMS) module$q$, $q$Provides document storage, versioning and retrieval capabilities that can be configured as a standalone DMS or combined with CRM data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$CRM and workflow configuration$q$, $q$Supports building customer relationship management and business-process workflows tailored to a company's specific operational needs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$SAP and enterprise IT integration$q$, $q$Native interfaces for connecting Limbas applications with SAP, ERP and groupware systems already in use at mid-sized and large organizations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$GPL v2 open-source licensing$q$, $q$Full source code is publicly available on GitHub, allowing self-hosting, auditing and modification without ongoing license fees.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Linux/Apache/PHP deployment$q$, $q$Runs on standard Linux server infrastructure with Apache and PHP 8 or later, fitting into existing on-premises IT environments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$LIMBAS live hosted option$q$, $q$A commercially supported, hosted version of the platform for organizations that want managed infrastructure and vendor support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Free, GPL-licensed core framework with no per-seat licensing costs for self-hosted use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Highly flexible: one framework can cover CRM, DMS, ERP and groupware needs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Native connectivity to enterprise databases including SAP MaxDB, Oracle and MSSQL$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Nearly three decades of operating history and open-source project delivery experience$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Full source code access supports data sovereignty and on-premises deployment requirements$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Requires PHP and Linux server administration skills to self-host and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Small open-source community and GitHub following compared to modern low-code tools like Baserow or NocoDB$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Documentation and community support skew toward German-speaking users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Dated interface conventions compared to newer visual, drag-and-drop app builders$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Custom implementation work can require significant consulting engagement to get real value$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Is Limbas free to use$q$, $q$The core OpenLIMBAS framework is free and open source under the GNU GPL v2.0 license for self-hosted deployments. The commercially hosted LIMBAS live offering and professional services are priced separately.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$What is Limbas used for$q$, $q$Limbas is a low-code database framework used to build custom CRM, document management (DMS), ERP, groupware and CMS applications on top of existing enterprise databases.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$What databases does Limbas support$q$, $q$Limbas connects to PostgreSQL, MySQL, Microsoft SQL Server, Oracle and SAP MaxDB or HANA via PDO and unixODBC.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Who develops Limbas$q$, $q$Limbas is developed and maintained by LIMBAS GmbH, a German software company headquartered in Oberhaching, Bavaria, that has worked in the open-source software space since 1996.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Does Limbas require coding knowledge$q$, $q$Limbas is a low-code platform, so many tasks can be done through its form and workflow builder, but self-hosting and deeper customization generally require PHP and Linux server administration skills.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$How does Limbas compare to Baserow or NocoDB$q$, $q$Limbas offers deeper native connectivity to enterprise databases like SAP MaxDB and Oracle, while Baserow and NocoDB provide more modern, spreadsheet-style interfaces and larger open-source communities.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Internal CRM for mid-sized companies$q$, $q$Companies build a tailored customer relationship management system on Limbas that reflects their specific sales process rather than adapting to a rigid commercial CRM.$q$, $q$Mid-sized businesses with in-house IT or PHP development capacity$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Document management for regulated industries$q$, $q$Organizations use the Limbas DMS module to store, version and retrieve documents on-premises, supporting data sovereignty requirements.$q$, $q$Public sector and regulated European organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$Custom database front-end over SAP and legacy systems$q$, $q$IT teams use Limbas to build a unified application layer over Oracle, MSSQL or SAP MaxDB databases already in production.$q$, $q$Enterprise IT departments integrating multiple legacy systems$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$OpenLIMBAS (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["GPL v2 licensed source code","Self-hosted on Linux/Apache/PHP","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$LIMBAS live (Hosted)$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Managed hosting","Vendor support","Implementation services"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Limbas is an open-source, low-code database application framework maintained by LIMBAS GmbH, a German software company based in Oberhaching, Bavaria, that has worked in the open-source space since 1996. Rather than shipping as a single finished product, Limbas provides a graphical database front-end and application-building layer that development teams use to construct custom CRM, DMS, ERP, groupware and CMS systems on top of existing enterprise databases.$q$, $q$The framework connects to a wide range of relational databases including PostgreSQL, MySQL, Microsoft SQL Server, Oracle and SAP MaxDB or HANA, and is released under the GNU GPL v2.0, meaning the full source is available and self-hostable at no license cost.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Limbas offers a form and workflow builder for creating data-entry interfaces without extensive custom coding, ODBC and native connectors for integrating with SAP and other enterprise IT systems, and configurable modules that have been used to implement CRM, document management and test-equipment tracking systems.$q$, $q$Because it is framework-based rather than a fixed vertical application, Limbas is most valuable to organizations with in-house PHP or low-code development capacity, or those working with LIMBAS GmbH consultants, who can assemble a system tailored to specific internal processes rather than adapting to a rigid, pre-built product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core OpenLIMBAS framework is free to download and self-host under its GPL license. LIMBAS GmbH generates revenue through professional services, custom implementation, and a commercially hosted offering called LIMBAS live, which bundles managed hosting and support for organizations that prefer not to run the software themselves.$q$, $q$Because pricing for hosting and services is quoted per engagement, prospective users typically need to contact LIMBAS GmbH directly for a custom quote rather than selecting from published subscription tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a77d14f1-cb26-4d11-9d26-6fc0a6e26e61', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Free, self-hosted Community Edition$q$, $q$Fully open-source, GPL-licensed survey software that can be downloaded and run on any PHP-compatible server at no license cost.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$LimeSurvey Cloud hosting$q$, $q$A managed SaaS version priced by response volume rather than gated features, available across seven hosting regions including the EU, UK, US, Canada and Australia.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Advanced survey logic$q$, $q$Supports branching, quotas, randomization and conditional question logic for complex research and market-research surveys.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Extensive localization$q$, $q$Survey interfaces and templates are available in 116 languages and dialects, supporting multilingual and international research projects.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$White-label and custom branding$q$, $q$Available on Expert tier and above, allowing organizations to present surveys under their own domain and visual identity.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$SSO and enterprise access control$q$, $q$LDAP and SAML single sign-on are available on the Corporate tier for organizations needing centralized authentication.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$REST API and integrations$q$, $q$Programmatic access for embedding surveys, exporting data and integrating with other research or CRM systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Data residency options$q$, $q$Seven hosting regions let organizations keep survey data within specific jurisdictions for GDPR or compliance purposes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Free, fully open-source self-hosted option with no feature restrictions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Response-based cloud pricing can be more predictable than per-seat SaaS competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Exceptional localization with 116 supported languages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Long operating history (since 2003) and mature, stable codebase$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Multiple hosting regions support GDPR and data-residency needs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Self-hosting requires PHP server administration knowledge and ongoing maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Interface feels less modern than newer competitors like Typeform$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Cloud pricing based on response volume can become costly for very high-traffic surveys$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Small company size (under 25 employees) means comparatively limited support capacity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Advanced features like white-labeling and SSO are locked behind higher-priced tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Is LimeSurvey free$q$, $q$Yes, the self-hosted Community Edition is free and open source under the GPL license. LimeSurvey Cloud, the hosted version, has a limited free tier and then paid plans starting around 29 to 34 euros per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Who owns LimeSurvey$q$, $q$LimeSurvey is developed and commercially operated by LimeSurvey GmbH, a company founded in August 2015 and headquartered in Hamburg, Germany, led by Carsten Schmitz.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$How is LimeSurvey Cloud priced$q$, $q$LimeSurvey Cloud pricing is based primarily on the number of survey responses collected per month or year, rather than on locking features behind higher tiers, with plans ranging from a free tier to a custom-quoted Corporate plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Can I self-host LimeSurvey$q$, $q$Yes, LimeSurvey's Community Edition can be downloaded and self-hosted on any server running PHP with a supported database such as MySQL, PostgreSQL, SQLite or MSSQL.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$How many languages does LimeSurvey support$q$, $q$LimeSurvey is localized into 116 languages and dialects, making it one of the most internationally capable open-source survey tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$What is the difference between LimeSurvey and SurveyMonkey$q$, $q$LimeSurvey offers a free, open-source self-hosted option and response-based cloud pricing, while SurveyMonkey is a closed-source commercial SaaS tool with feature-gated subscription tiers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Academic and market research$q$, $q$Universities and research teams use LimeSurvey's advanced logic, quotas and multilingual support to run complex studies.$q$, $q$Academic researchers and market research firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Public sector and nonprofit surveys$q$, $q$Organizations self-host LimeSurvey to maintain full data control and avoid per-response SaaS fees, aided by nonprofit discounts.$q$, $q$Government agencies and nonprofit organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Multilingual international surveys$q$, $q$Companies and NGOs run surveys across many countries using LimeSurvey's 116-language localization.$q$, $q$International organizations and multinational businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted, GPL licensed","Unlimited surveys and questions","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Basic (Cloud)$q$, $q$EUR 34/month$q$, $q$Monthly$q$, NULL, $q$["1 admin user","1,000 responses/month","250 MB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Expert (Cloud)$q$, $q$EUR 29/month (billed annually)$q$, $q$Annual$q$, NULL, $q$["3 admin users","10,000 responses/year","White-label domain","Email support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Business (Cloud)$q$, $q$EUR 75/month (billed annually)$q$, $q$Annual$q$, NULL, $q$["5-10 admin users","50,000 responses/year","Alias domain","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$Corporate (Cloud)$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["SSO via LDAP/SAML","Dedicated server","VIP support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LimeSurvey began life in 2003 as PHPSurveyor, an open-source survey tool created by Australian developer Jason Cleeland, and was renamed LimeSurvey in 2007. LimeSurvey GmbH, the company that now stewards the project, was formally founded in August 2015 in Hamburg, Germany, and is led by long-time project leader Carsten Schmitz.$q$, $q$The software is available as a free, GPL-licensed, self-hosted Community Edition, and as LimeSurvey Cloud, a paid hosted service whose pricing is based on survey response volume rather than feature restrictions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LimeSurvey supports unlimited surveys and questions, advanced survey logic such as branching and quotas, and localization into 116 languages, making it one of the most internationally capable survey platforms available.$q$, $q$The platform runs on PHP with the Yii framework and Twig templating, supports MySQL, PostgreSQL, SQLite or MSSQL as a database backend, and offers white-label branding, custom domains, and SSO options (LDAP, SAML) on higher cloud tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LimeSurvey Cloud offers a free entry tier with limited monthly responses, then scales through Basic (about 34 euros per month), Expert (about 29 euros per month billed annually), Business (about 75 euros per month billed annually) and a custom-quoted Corporate tier with SSO and dedicated hosting.$q$, $q$The self-hosted Community Edition remains free under the GPL license for organizations able to manage their own server infrastructure, with discounts available for teachers, students and nonprofits on the Cloud plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ea21bbfa-3554-42a3-a4a1-7aac41c0974f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$No-code AI agent builder$q$, $q$Create autonomous AI agents (Lindies) using natural-language instructions rather than technical workflow diagrams.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Built-in approval workflow$q$, $q$Agents draft emails and actions for explicit human review and approval before anything is sent, keeping a human in the loop.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Meeting notes and action items$q$, $q$Lindy can join video calls, record and transcribe meetings, and automatically extract action items and summaries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$100+ integrations$q$, $q$Connects to Gmail, Outlook, Slack, Notion, HubSpot, Salesforce, Microsoft Teams, Zoom and dozens of other business tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Computer use (browser automation)$q$, $q$Available on Pro tier and above, letting agents control a web browser to complete tasks without a native API integration.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$iMessage and SMS access$q$, $q$Users can interact with their AI agents directly via text message or iMessage around the clock.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Enterprise security and compliance$q$, $q$Enterprise plan includes SSO, SCIM provisioning, HIPAA compliance, audit logs and a signed business associate agreement.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Privacy-first data handling$q$, $q$Lindy states customer data is not sold or used to train underlying models without consent.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Natural-language agent creation requires no coding or technical workflow design$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Built-in human approval step reduces risk of fully autonomous AI mistakes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Broad integration library covering the most common business tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Well-funded startup (50 million dollars raised) with strong investor backing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Enterprise tier supports regulated industries via HIPAA compliance and audit logs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$No persistent free tier, only a 7-day trial before payment is required$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Higher tiers (Pro and Max) needed to unlock browser-based computer use and heavier usage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Relatively young company (founded 2023) with a limited multi-year track record$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Enterprise pricing is custom and not published, requiring a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Usage-based limits across plans can be difficult to predict for high-volume workflows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$What is Lindy used for$q$, $q$Lindy is used to build no-code AI agents that automate business tasks such as email management, meeting scheduling, note-taking, lead qualification and customer support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$How much does Lindy cost$q$, $q$Lindy's Plus plan starts at 49.99 dollars per month, with Pro at 99.99 dollars and Max at 199.99 dollars per month. An Enterprise plan with custom pricing is available for larger organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Who founded Lindy$q$, $q$Lindy was founded in 2023 by Flo Crivello and is headquartered in San Francisco, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Does Lindy have a free plan$q$, $q$Lindy does not offer a permanent free plan, but all individual paid plans include a 7-day free trial that does not require a credit card.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$What is computer use in Lindy$q$, $q$Computer use is a feature available on Lindy's Pro plan and above that allows an AI agent to control a web browser directly to complete tasks that do not have a native API integration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Is Lindy suitable for regulated industries like healthcare$q$, $q$Lindy's Enterprise plan includes HIPAA compliance, audit logs and a signed business associate agreement, making it usable for healthcare-related workflows that involve protected health information.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Inbox and calendar automation$q$, $q$Individual professionals use Lindy to triage email, draft responses in their own voice and manage scheduling automatically.$q$, $q$Founders, executives and busy professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Sales lead qualification$q$, $q$Sales teams deploy Lindy agents to qualify inbound leads and route them appropriately before a human rep engages.$q$, $q$Sales and revenue operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Automated customer support triage$q$, $q$Support teams use Lindy to handle first-line ticket responses and escalate complex issues to human agents.$q$, $q$Customer support teams at growing companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Plus$q$, $q$$49.99/month$q$, $q$Monthly$q$, NULL, $q$["Up to 2 connected inboxes","Standard usage limits","100+ integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Pro$q$, $q$$99.99/month$q$, $q$Monthly$q$, NULL, $q$["3x Plus usage","Up to 3 inboxes","Computer use (browser automation)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Max$q$, $q$$199.99/month$q$, $q$Monthly$q$, NULL, $q$["7x Plus usage","Up to 5 inboxes","All Pro features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["SSO and SCIM provisioning","HIPAA compliance","Audit logs and signed BAA","Dedicated support and onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lindy is a no-code AI agent platform founded in 2023 by Flo Crivello and based in San Francisco. The company has raised approximately 50 million dollars in Series A funding led by Battery Ventures, with backing from a16z, Menlo Ventures, Coatue and Tiger Global.$q$, $q$Lindy lets users build AI agents, called Lindies, that automate tasks like email management, scheduling, meeting notes, lead qualification and customer support, connecting to over 100 business tools including Gmail, Slack, Notion, HubSpot and Salesforce.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include natural-language agent creation, an approval workflow where agents draft actions for human review before sending, meeting joining and note-taking with action-item extraction, and iMessage/SMS access for interacting with agents outside a web browser.$q$, $q$Higher tiers add computer use, which lets an agent control a web browser directly to complete tasks that lack a native API integration, along with enterprise-grade security features like SSO, SCIM and HIPAA compliance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lindy offers three self-serve monthly plans: Plus at 49.99 dollars, Pro at 99.99 dollars, and Max at 199.99 dollars, each scaling usage limits and the number of connected inboxes, with Pro and above adding browser-based computer use.$q$, $q$A custom-quoted Enterprise plan adds SSO, SCIM provisioning, HIPAA compliance, audit logs and a signed BAA. All individual plans include a 7-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5420efbb-d040-4bba-98e1-eb3de9843667', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Cycles (sprint management)$q$, $q$Time-boxed work cycles that help teams plan and track focused iterations of work, Linear's equivalent to sprints.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Triage queue$q$, $q$A dedicated queue for incoming issues and bug reports that need to be classified before entering the active workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Keyboard-first, high-speed interface$q$, $q$Built with a local-first architecture for near-instant navigation and an extensive set of keyboard shortcuts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Roadmaps and project tracking$q$, $q$Connects individual issues to larger projects and initiatives for visibility across teams and leadership.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Triage Intelligence and Linear Agent (AI)$q$, $q$AI-assisted issue classification and beta agent automations available on the Business tier and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Code Intelligence (beta)$q$, $q$Connects issues directly to related code changes and pull requests for engineering traceability.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Guest accounts and private teams$q$, $q$Business tier supports external collaborators via guest accounts and restricts visibility with private teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Enterprise identity and billing controls$q$, $q$SAML and SCIM support, invoice and purchase-order billing, and granular admin controls on the Enterprise plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Widely praised for interface speed and design quality compared to legacy tools like Jira$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Generous free tier supports small teams with unlimited members$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Strong backing from Sequoia and Accel with a 1.25 billion dollar valuation signaling long-term stability$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Opinionated Linear Method reduces process overhead for engineering teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Increasing AI-assisted features (Triage Intelligence, Code Intelligence) built directly into the workflow$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Free plan caps out at 250 issues and 2 teams, requiring an upgrade for growing teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Advanced AI and automation features are gated behind the higher-priced Business tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Enterprise pricing is not published and requires custom sales negotiation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Less configurable than Jira for teams with complex, non-standard workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Opinionated workflow model may not suit teams outside software engineering$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Is Linear free$q$, $q$Linear offers a free plan with unlimited members, up to 2 teams and 250 issues. Paid plans start at 10 dollars per user per month billed yearly for more teams and unlimited issues.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Who founded Linear$q$, $q$Linear was founded in 2019 by Karri Saarinen, Tuomas Artman and Jori Lallo, and is headquartered in San Francisco, California.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$How much funding has Linear raised$q$, $q$Linear has raised approximately 134.2 million dollars in total funding, including an 82 million dollar Series C in June 2025 at a 1.25 billion dollar valuation, led by Accel.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$What is the Linear Method$q$, $q$The Linear Method is Linear's opinionated set of best practices for software development workflow, emphasizing short focused work cycles, clear issue ownership and minimal process overhead.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$How does Linear differ from Jira$q$, $q$Linear focuses on speed, a minimalist interface and an opinionated workflow, while Jira offers extensive configurability and a broader feature set aimed at larger, more complex organizations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Does Linear have AI features$q$, $q$Yes, Linear's Business plan includes Triage Intelligence for AI-assisted issue classification, along with beta Linear Agent automations and Code Intelligence.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Software engineering issue tracking$q$, $q$Engineering teams use Linear to track bugs, features and technical debt with a fast, keyboard-driven interface.$q$, $q$Software engineering teams at startups and tech companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Product roadmap planning$q$, $q$Product managers connect individual issues to broader initiatives and roadmaps for cross-team visibility.$q$, $q$Product managers and engineering leadership$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Startup sprint and cycle management$q$, $q$Early-stage and high-growth startups use Linear's Cycles feature to run structured, time-boxed sprints with minimal overhead.$q$, $q$Venture-backed startups and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited members","2 teams, 250 issues","Agent platform access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Basic$q$, $q$$10/user/month$q$, $q$Annual$q$, NULL, $q$["5 teams, unlimited issues","Unlimited file uploads","Admin roles"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Business$q$, $q$$16/user/month$q$, $q$Annual$q$, NULL, $q$["Unlimited teams","Private teams and guest accounts","Triage Intelligence, Linear Agent (beta)","Zendesk and Intercom integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["SAML and SCIM","Invoice/PO billing","Priority support with account manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Linear was founded in 2019 by Karri Saarinen, Tuomas Artman and Jori Lallo, and is headquartered in San Francisco. The company has raised roughly 134.2 million dollars in total funding, most recently an 82 million dollar Series C led by Accel in June 2025 at a 1.25 billion dollar valuation.$q$, $q$Linear is used by more than 33,000 companies, including OpenAI, Coinbase and Ramp, and is built around the Linear Method, an opinionated approach to software development workflow that emphasizes speed, focus and minimal process overhead.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core product features include Cycles for time-boxed sprints, a Triage queue for incoming issues, project and roadmap tracking, and an extensive keyboard-shortcut-driven interface built for speed.$q$, $q$Higher tiers add AI-assisted Triage Intelligence, beta Linear Agent automations and Code Intelligence, Linear Insights analytics, and integrations with tools like Zendesk and Intercom.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e762d0b5-3f6a-4165-89d8-5d2a4889217d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Linear offers a free plan (unlimited members, 2 teams, 250 issues), a Basic plan at 10 dollars per user per month billed yearly, and a Business plan at 16 dollars per user per month billed yearly with AI and automation features.$q$, $q$An Enterprise plan offers custom, annual-only pricing with SAML/SCIM, invoice billing and dedicated support for larger organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Internet Archive auto-backup$q$, $q$Every saved link is automatically submitted to the Wayback Machine, protecting against link rot even if the original page disappears.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Dead link monitoring$q$, $q$LinkAce periodically checks saved links and notifies users if a site has moved or become unavailable.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Tags and custom lists$q$, $q$Bookmarks can be organized simultaneously by tags and by custom lists grouped around topics or occasions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Multi-user support with SSO$q$, $q$Supports multiple users with internal sharing plus OAuth and OIDC single sign-on for centralized authentication.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$REST API and Zapier integration$q$, $q$Full REST API for custom integrations, plus native Zapier support connecting to thousands of other applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Docker and Kubernetes deployment$q$, $q$Ships with pre-configured Docker setups and a web installer, with beta support for Kubernetes deployments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$HTML import and export$q$, $q$Migrate bookmarks in and out of LinkAce using standard browser-compatible HTML bookmark files.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Multilingual interface$q$, $q$Available in English, German, French, Japanese, Spanish, Polish and Chinese.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Completely free and open source with no paid tier or vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Automatic Internet Archive backup protects against link rot uniquely well among bookmark managers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Rich built-in feature set including multi-provider SSO and Zapier integration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Full REST API supports deep custom integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Active, ongoing development with regular releases as of 2026$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Requires self-hosting via Docker, which demands basic server administration skills$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Smaller community (about 3,300 GitHub stars) than close competitor linkding$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Heavier Laravel/PHP stack compared to more minimal self-hosted alternatives$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$No official hosted/cloud version for non-technical users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Maintained largely by a single core developer, creating bus-factor risk$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Is LinkAce free$q$, $q$Yes, LinkAce is completely free and open source under the GPL-3.0 license, with no paid tiers or hosted commercial version.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Who created LinkAce$q$, $q$LinkAce was created by German developer Kevin Woblick, known online as Kovah, who released version 1.0 on December 15, 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$How is LinkAce different from linkding$q$, $q$LinkAce is built on Laravel/PHP and offers a richer built-in feature set including multi-provider SSO and native Zapier integration, while linkding is built on Django/Python and is generally considered more minimal and lightweight, with a larger GitHub community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Does LinkAce back up bookmarks automatically$q$, $q$Yes, every link saved in LinkAce is automatically submitted to the Internet Archive Wayback Machine, protecting against link rot if the original page goes offline.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$How do I install LinkAce$q$, $q$LinkAce is designed to be deployed via Docker using pre-configured setups and a built-in web installer, with beta support for Kubernetes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Does LinkAce support multiple users$q$, $q$Yes, LinkAce supports multi-user deployments with internal sharing and single sign-on via OAuth or OIDC providers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Personal knowledge archiving$q$, $q$Individuals use LinkAce to build a permanent, searchable archive of reference links that survives even if the original pages go offline.$q$, $q$Researchers, writers and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Self-hosted privacy-focused bookmarking$q$, $q$Privacy-conscious users run LinkAce on home servers or NAS devices to avoid trusting bookmark data to third-party cloud services.$q$, $q$Self-hosting hobbyists and privacy-focused individuals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Small team shared link libraries$q$, $q$Small teams use LinkAce's multi-user support and SSO to maintain a shared, tagged library of resource links.$q$, $q$Small businesses and community organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["GPL-3.0 licensed source code","Docker and Kubernetes (beta) deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LinkAce is a free, open-source, self-hosted bookmark archiving tool created by German developer Kevin Woblick (Kovah), with its first stable release, version 1.0, launched on December 15, 2020. It is licensed under GPL-3.0 and built on the Laravel PHP framework, distributed primarily as a Docker deployment.$q$, $q$The project has no associated company; it is maintained as a community open-source project on GitHub, where it has accumulated roughly 3,300 stars, with active releases continuing through 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LinkAce organizes bookmarks with both tags and custom lists, monitors saved links for availability, and automatically archives every saved page to the Internet Archive for long-term preservation against link rot.$q$, $q$It supports multi-user access with OAuth and OIDC single sign-on, exposes a full REST API, integrates with Zapier for connecting to thousands of other apps, and offers HTML import/export and S3-compatible backups.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LinkAce is completely free and open source under the GPL-3.0 license, with no paid tier or hosted commercial version; users are responsible for their own server or Docker hosting infrastructure.$q$, $q$Because there is no company behind LinkAce, ongoing development relies on community contributions and voluntary maintenance rather than subscription revenue.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0a589b88-3042-41c7-8ea2-df2e6f517ac7', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Minimal, fast Docker setup$q$, $q$Designed from the ground up to be lightweight and quick to deploy using a single Docker container or Docker Compose.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Tag-based organization with bulk editing$q$, $q$Organize bookmarks with tags and edit many bookmarks at once for efficient large-scale library management.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Automatic metadata extraction and archiving$q$, $q$Automatically pulls page titles, descriptions and favicons, and can archive full page content locally or to the Internet Archive.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Markdown notes and read-it-later workflow$q$, $q$Attach Markdown-formatted notes to bookmarks and use built-in read-it-later status tracking.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Bookmark sharing with users and guests$q$, $q$Share individual bookmarks with other registered users or anonymous guests via shareable links.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$REST API and admin panel$q$, $q$Full REST API and Django admin panel support third-party clients and administrative user management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$PWA and browser extensions$q$, $q$Installable as a Progressive Web App on mobile, with dedicated Firefox and Chrome browser extensions and a bookmarklet.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$SSO via OIDC and auth proxies$q$, $q$Supports single sign-on through OIDC providers or generic authentication proxies for centralized login.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Free, open source under the permissive MIT license with no paid tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Large, active GitHub community (about 10,900 stars), among the most popular self-hosted bookmark managers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Minimal resource footprint and fast performance, ideal for low-powered home servers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Rich third-party ecosystem of community-built clients and integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Regular, steady release cadence indicating strong ongoing maintenance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Requires Docker and basic self-hosting knowledge to deploy$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Smaller built-in feature set than LinkAce, for example no native Zapier integration$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$No official hosted or cloud version for non-technical users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Maintained primarily by a single core developer, creating dependency risk$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$No multi-provider SSO beyond OIDC and auth proxies (no native OAuth provider list like LinkAce)$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Is linkding free$q$, $q$Yes, linkding is completely free and open source under the MIT license, with no paid tiers or subscription costs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Who created linkding$q$, $q$Linkding was created by developer Sascha Ißbrücker, known on GitHub as sissbruecker, with the project first released around 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$What is the difference between linkding and LinkAce$q$, $q$Linkding is built on Django/Python and emphasizes minimalism, speed and simple Docker setup with a larger GitHub community, while LinkAce is built on Laravel/PHP and offers a richer built-in feature set including multi-provider SSO and native Zapier integration.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$What database does linkding use$q$, $q$Linkding uses SQLite by default for zero-configuration setup, and also supports PostgreSQL as an alternative database backend.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Can linkding archive full web pages$q$, $q$Yes, linkding can archive saved pages either as a local HTML snapshot or by submitting them to the Internet Archive's Wayback Machine.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Does linkding have browser extensions$q$, $q$Yes, linkding offers dedicated browser extensions for Firefox and Chrome, plus a bookmarklet and installable Progressive Web App support.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Lightweight personal bookmark management$q$, $q$Individuals who want a fast, no-frills self-hosted bookmark manager use linkding for its minimal setup and clean interface.$q$, $q$Developers and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Home lab and NAS deployment$q$, $q$Users running home labs or NAS devices deploy linkding for its small resource footprint and simple Docker Compose setup.$q$, $q$Home lab and NAS users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Privacy-focused bookmark ownership$q$, $q$Users who want to avoid third-party cloud bookmarking services self-host linkding to retain full control of their data.$q$, $q$Privacy-conscious individuals and technical teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT licensed source code","Docker and Docker Compose deployment","Community support and third-party clients"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Linkding is a free, open-source, self-hosted bookmark manager created by developer Sascha Ißbrücker (GitHub handle sissbruecker), first released around 2020 and distributed under the MIT license. It is one of the most popular self-hosted bookmark managers, with roughly 10,800 to 10,900 GitHub stars as of 2026.$q$, $q$Built with Python and Django on the backend and SQLite by default (with optional PostgreSQL support), linkding is explicitly designed to be minimal, fast, and easy to set up using Docker.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include tag-based organization with bulk editing, Markdown notes on bookmarks, read-it-later functionality, and bookmark sharing with other users or anonymous guests via shareable links.$q$, $q$Linkding automatically extracts page metadata, can archive full pages locally or to the Internet Archive, supports Netscape HTML import/export, and is installable as a Progressive Web App with dedicated Firefox and Chrome browser extensions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Linkding is entirely free and open source under the MIT license, with no company, paid tier or hosted commercial offering; users self-host it via Docker or Docker Compose.$q$, $q$There is no subscription cost or usage limit since the software is community-maintained rather than operated as a commercial SaaS product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8026be73-ac41-420c-b94b-3ca165f049ef', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$40+ advanced search filters$q$, $q$Search by job title, location, skills, industry, language and network relationship to precisely target candidates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$InMail messaging$q$, $q$Send direct messages to candidates outside a recruiter's existing network, with monthly allotments varying by plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Recommended Matches$q$, $q$Algorithmically surfaces candidates a recruiter has not yet searched for, based on job postings and real-time hiring signals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Hiring Assistant (AI add-on)$q$, $q$Automates profile review, prescreening questions and message drafting while keeping recruiters in control of decisions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Spotlight filters$q$, $q$Highlights receptive candidates using signals like Open to Work, Active Talent and Rediscovered Candidates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Team collaboration and analytics$q$, $q$Corporate tier includes shared pipelines, team performance analytics and collaboration tools for recruiting teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$ATS and CRM integrations$q$, $q$Connects with applicant tracking systems and other LinkedIn recruiting products for a unified hiring workflow.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Talent Insights (separate product)$q$, $q$A standalone labor-market analytics tool providing hiring trend and competitor hiring data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Unmatched first-party access to LinkedIn's 1 billion-plus member professional network$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Real-time job-seeking signals (Open to Work, Active Talent) unavailable to most third-party tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$AI-assisted Hiring Assistant reduces manual profile review while keeping humans in the loop$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Deep integrations with ATS and other LinkedIn recruiting products$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Backed by data showing higher first-year retention for LinkedIn-sourced hires$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$High per-seat cost, especially for Recruiter Corporate at roughly 900 dollars per month per seat$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$No shared or floating licenses, so costs scale linearly with team size$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Top-tier Corporate pricing is not publicly published and requires sales negotiation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Recruiter Lite's InMail allotment and network access are meaningfully limited$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Talent Insights is sold as a separate, additional-cost product rather than being bundled in$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$How much does LinkedIn Recruiter cost$q$, $q$Recruiter Lite costs approximately 170 dollars per month for individual recruiters, while Recruiter Corporate costs roughly 900 dollars per month, or about 10,800 dollars annually, per individual seat, with pricing ultimately negotiated with LinkedIn sales.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$What is the difference between Recruiter Lite and Recruiter Corporate$q$, $q$Recruiter Lite offers 20 search filters, third-degree network access and about 30 InMails per month, while Recruiter Corporate offers 40-plus filters, unrestricted network access, 100 to 150 InMails per month, and team collaboration and analytics tools.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Who owns LinkedIn Recruiter$q$, $q$LinkedIn Recruiter is a product of LinkedIn, which has been a wholly owned subsidiary of Microsoft since its 2016 acquisition for approximately 26.2 billion dollars.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$What is LinkedIn Hiring Assistant$q$, $q$Hiring Assistant is an AI-powered add-on to LinkedIn Recruiter that automates repetitive tasks like profile review, prescreening questions and message drafting, while keeping the human recruiter in control of final decisions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Does LinkedIn Recruiter require a separate license per user$q$, $q$Yes, LinkedIn requires each recruiter or sourcer to hold an individual Recruiter seat license, with no shared or floating licenses available across a team.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$What is LinkedIn Talent Insights$q$, $q$Talent Insights is a separate LinkedIn analytics product providing labor-market data such as hiring trends, talent availability and competitor hiring activity, typically priced between 6,000 and 20,000 dollars per year.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$High-volume enterprise recruiting$q$, $q$In-house talent acquisition teams use Recruiter Corporate's full search depth and InMail volume to source candidates at scale.$q$, $q$Enterprise talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Occasional hiring by small businesses$q$, $q$Hiring managers who recruit infrequently use Recruiter Lite for a lower-cost entry point into LinkedIn's candidate database.$q$, $q$Small business owners and hiring managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Staffing and executive search agencies$q$, $q$Agencies use LinkedIn Recruiter's advanced filters and Spotlight features to source candidates across multiple client searches simultaneously.$q$, $q$Staffing agencies and executive recruiters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Recruiter Lite$q$, $q$~$170/month$q$, $q$Monthly or annual$q$, NULL, $q$["20 search filters","Access up to 3rd-degree connections","~30 InMails per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Recruiter Corporate$q$, $q$~$900/month (~$10,800/year) per seat$q$, $q$Annual, per seat$q$, NULL, $q$["40+ advanced search filters","Unrestricted network access","100-150 InMails per month","Recommended Matches and team analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$Talent Insights (add-on)$q$, $q$$6,000-$20,000/year$q$, $q$Annual$q$, NULL, $q$["Labor-market and hiring trend analytics","Competitor hiring activity data"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LinkedIn Recruiter is the primary talent sourcing product within LinkedIn Talent Solutions, operated by LinkedIn, a Microsoft subsidiary headquartered in Sunnyvale, California, with more than 1 billion members on its underlying professional network.$q$, $q$The product gives recruiters direct search and outreach access to LinkedIn's member graph, differentiating it from third-party sourcing tools that lack first-party access to LinkedIn's real-time job-seeking and engagement data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LinkedIn Recruiter Corporate provides more than 40 advanced search filters, unrestricted network access, 100 to 150 InMail messages per month, and Recommended Matches, an algorithmic feature surfacing candidates recruiters have not yet searched for.$q$, $q$The Hiring Assistant add-on layers AI automation onto profile review, prescreening and message drafting while keeping recruiters in control of final hiring decisions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5edf3623-fbe7-4031-ae06-d836d7bc2e06', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Recruiter Lite is priced around 170 dollars per month for individual recruiters with limited filters and InMail volume, while Recruiter Corporate runs approximately 900 dollars per month, or about 10,800 dollars per year, per individual seat, with no shared or floating licenses.$q$, $q$The separate Talent Insights analytics product is typically priced between 6,000 and 20,000 dollars per year, and pricing for Recruiter Corporate is otherwise negotiated directly with LinkedIn sales.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$AI-powered contract repository (Analyze)$q$, $q$Automatically extracts key terms, dates, obligations and risk factors from existing contracts using NLP and machine learning.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Contract drafting and negotiation (Finalize)$q$, $q$Templated drafting, redlining, negotiation tracking and approval workflows for new contracts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Integrated e-signature$q$, $q$Built-in e-signature capabilities to move contracts from draft to fully executed without leaving the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$LinkAI agentic automation$q$, $q$AI agents that can autonomously execute multi-step contract review and management tasks rather than just surfacing data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Obligation and renewal tracking$q$, $q$Automated alerts for key dates, renewals and contractual obligations across a full contract portfolio.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Reporting and analytics dashboards$q$, $q$Turns unstructured contract archives into searchable, reportable data for legal and finance teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Custom workflow and approval routing$q$, $q$Configurable approval chains for contract review and sign-off across departments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Integrations with business systems$q$, $q$Connects with CRM, ERP and other business systems to keep contract data aligned with broader operations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$AI-first platform with deep natural language extraction for existing contract archives$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Combines contract analytics and contract creation/negotiation in a single platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Well-funded (approximately 164 million dollars raised), suggesting product longevity and continued investment$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Strong reported ROI on time savings for legal and contract operations teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Growing agentic AI feature set (LinkAI) ahead of many CLM competitors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Pricing is entirely custom and not published, complicating budget comparisons$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Reported total cost of ownership can be high, with enterprise deployments exceeding 75,000 dollars per year$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Add-on costs for e-signature, API access and advanced AI can add 20-40 percent to quoted price$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Implementation and onboarding fees can be substantial, sometimes up to a full year's license cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Best suited to organizations with meaningful contract volume, less cost-effective for very small teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$How much does LinkSquares cost$q$, $q$LinkSquares uses custom, quote-based pricing structured around contract volume, user count and feature tier. Market research suggests a median annual cost of around 31,000 dollars, with enterprise deployments sometimes exceeding 75,000 dollars per year.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Who founded LinkSquares$q$, $q$LinkSquares was founded in 2015 in Boston, Massachusetts, by CEO Vishal Sunak and co-founder Chris Combs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$What is LinkAI$q$, $q$LinkAI is LinkSquares' branded AI layer woven throughout its contract lifecycle management platform, including agentic automation for multi-step contract tasks.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$What is the difference between LinkSquares Analyze and Finalize$q$, $q$Analyze is LinkSquares' AI-powered contract repository and analytics tool for existing agreements, while Finalize covers contract drafting, negotiation and e-signature workflows for new agreements.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$How much funding has LinkSquares raised$q$, $q$LinkSquares has raised approximately 164 million dollars in total funding from investors including Sorenson Capital, MassMutual Ventures and Hyperplane.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Who are LinkSquares' main competitors$q$, $q$LinkSquares' main competitors include Ironclad, DocuSign CLM, ContractPodAi, Icertis, Agiloft and Concord in the contract lifecycle management category.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Legal contract repository modernization$q$, $q$Legal teams migrate a large archive of unstructured contracts into LinkSquares Analyze to make terms and obligations searchable and reportable.$q$, $q$In-house legal and compliance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Sales contract drafting and negotiation$q$, $q$Sales operations teams use LinkSquares Finalize to speed up templated contract drafting, redlining and e-signature for new deals.$q$, $q$Sales operations and revenue teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Enterprise contract risk and renewal management$q$, $q$Enterprises use automated obligation and renewal tracking to reduce missed deadlines and contractual risk across large portfolios.$q$, $q$Enterprise legal operations and procurement teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Analyze$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["AI contract repository","Key term and obligation extraction","Reporting and analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Finalize$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Contract drafting and templates","Redlining and negotiation tracking","Integrated e-signature"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$Combined / Enterprise$q$, $q$Custom pricing (often $31,000+/year)$q$, $q$Annual$q$, NULL, $q$["Analyze plus Finalize combined","LinkAI agentic automation","Custom implementation and onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LinkSquares is an AI-powered contract lifecycle management (CLM) company founded in 2015 in Boston, Massachusetts, by CEO Vishal Sunak and co-founder Chris Combs. The company has raised approximately 164 million dollars in venture funding from investors including Sorenson Capital, MassMutual Ventures and Hyperplane.$q$, $q$LinkSquares helps legal, procurement and sales operations teams draft, negotiate, analyze and manage contracts, applying AI, branded as LinkAI, throughout the contract lifecycle to reduce manual review work.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform is organized around two core capabilities: Analyze, an AI-powered contract repository that extracts key terms, dates and obligations from existing agreements, and Finalize, a contract drafting, negotiation and e-signature workflow for new agreements.$q$, $q$LinkSquares increasingly markets itself as an agentic CLM, applying AI agents to automate multi-step contract tasks rather than simply surfacing data for manual review.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LinkSquares does not publish standardized pricing and requires a custom quote, structured around contract volume, number of users, and selected feature tier (Analyze, Finalize, or combined).$q$, $q$Third-party buyer research suggests a median annual cost of around 31,000 dollars, with per-user costs typically between 2,500 and 3,500 dollars annually, and enterprise deployments sometimes exceeding 75,000 dollars per year, plus potential add-on and implementation costs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95bdcbb9-6021-42d0-a5e2-e06607c0d49b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
